<?php ao_schema_ensure_v1200(); $rows=[]; try{$rows=db()->query('SELECT a.*, l.title, l.domain_name FROM marketplace_auctions a LEFT JOIN marketplace_listings l ON l.id=a.listing_id ORDER BY a.id DESC LIMIT 200')->fetchAll();}catch(Throwable $e){} ?>
<div class="ao-page-head"><div><h2>Marketplace Açık Artırma</h2><p>Başlangıç fiyatı, minimum artış, hemen al fiyatı ve bitiş zamanı yönetimi.</p></div></div>
<div class="ao-card"><table class="ao-table"><thead><tr><th>İlan</th><th>Başlangıç</th><th>Min. Artış</th><th>Hemen Al</th><th>Bitiş</th><th>Durum</th></tr></thead><tbody><?php foreach($rows as $r): ?><tr><td><?= e($r['domain_name'] ?: $r['title']) ?></td><td><?= number_format((float)$r['start_price'],2,',','.') ?></td><td><?= number_format((float)$r['min_increment'],2,',','.') ?></td><td><?= $r['buy_now_price'] ? number_format((float)$r['buy_now_price'],2,',','.') : '-' ?></td><td><?= e($r['ends_at']) ?></td><td><?= e($r['status']) ?></td></tr><?php endforeach; if(!$rows): ?><tr><td colspan="6">Açık artırma yok. İlan satış modelinden oluşturulacak.</td></tr><?php endif; ?></tbody></table></div>
